#!/usr/bin/env bash
set -euo pipefail

TARGET_DIR="${APP_DIR:-/app}"
cd "$TARGET_DIR"

# Keep the oracle self-contained: some runners expose only solve.sh rather than
# auxiliary files from the solution directory.
CBOR_SOURCE=''
VERIFIER_SOURCE=''
printf '%s' "$CBOR_SOURCE" | base64 -d > "$TARGET_DIR/internal/verifier/cbor.go"
printf '%s' "$VERIFIER_SOURCE" | base64 -d > "$TARGET_DIR/internal/verifier/verifier.go"
gofmt -w "$TARGET_DIR/internal/verifier/cbor.go" "$TARGET_DIR/internal/verifier/verifier.go"
go build -o "$TARGET_DIR/bin/backupguard" ./cmd/backupguard

